function e(t){return new Intl.NumberFormat("zh-CN").format(t)}function o(t){if(t.total_tokens!=null)return t.total_tokens;if(t.prompt_tokens!=null&&t.completion_tokens!=null)return t.prompt_tokens+t.completion_tokens}function a(t){return t<=0?"0s":`${(t/1e3).toFixed(1)}s`}function r(t,n){return n<=0?"0%":`${Math.round(t/n*100)}%`}function s(t){return t<500?"stats-latency-good":t<2e3?"stats-latency-warn":"stats-latency-bad"}export{e as a,r as b,o as d,a as f,s as l};
